def get_schema_info(connection_url: str) -> dict:
    engine = create_engine(connection_url)
    inspector = inspect(engine)
    schema = {}
    with engine.connect() as conn:
        for table in inspector.get_table_names():
            columns = [
                {
                    "name":        col["name"],
                    "type":        str(col["type"]),
                    "nullable":    col.get("nullable", True),
                    "primary_key": col.get("primary_key", False),
                }
                for col in inspector.get_columns(table)
            ]
            foreign_keys = [
                {
                    "column":            fk["constrained_columns"],
                    "references_table":  fk["referred_table"],
                    "references_column": fk["referred_columns"],
                }
                for fk in inspector.get_foreign_keys(table)
            ]
            try:
                row_count = conn.execute(text(f'SELECT COUNT(*) FROM "{table}"')).scalar()
            except Exception:
                row_count = None
            try:
                res = conn.execute(text(f'SELECT * FROM "{table}" LIMIT 3'))
                cols = res.keys()
                sample_rows = [{k: str(v) for k, v in zip(cols, row)} for row in res.fetchall()]
            except Exception:
                sample_rows = []
            schema[table] = {
                "columns":      columns,
                "foreign_keys": foreign_keys,
                "row_count":    row_count,
                "sample_rows":  sample_rows,
            }
    engine.dispose()
    return schema

def schema_to_prompt_text(schema: dict) -> str:
    lines = []
    for table, info in schema.items():
        lines.append(f"Table: {table} ({info['row_count']} rows)")
        for col in info["columns"]:
            pk   = " [PK]" if col["primary_key"] else ""
            null = "" if col["nullable"] else " NOT NULL"
            lines.append(f"  - {col['name']} ({col['type']}){pk}{null}")
        lines.append("")
    return "\n".join(lines)

def explain_sql_error(original_question, failed_sql, error_message, schema_context="") -> dict:
    llm = ChatGroq(model=settings.GROQ_MODEL, temperature=0, groq_api_key=settings.GROQ_API_KEY)
    system = """You are a database expert. Explain the SQL error simply, provide corrected SQL, and give a tip.
Respond ONLY in this JSON format: {"explanation": "...", "fix": "...", "tip": "..."}"""
    user = f"Question: {original_question}\nFailed SQL: {failed_sql}\nError: {error_message}\nSchema: {schema_context}"
    try:
        response = llm.invoke([SystemMessage(content=system), HumanMessage(content=user)])
        content = response.content.strip().replace("```json", "").replace("```", "").strip()
        result = json.loads(content)
        result["success"] = True
        return result
    except Exception as e:
        return {"success": False, "explanation": str(e), "fix": "", "tip": ""}

def suggest_followup_questions(original_question, sql_result_summary, schema_context) -> list:
    llm = ChatGroq(model=settings.GROQ_MODEL, temperature=0.7, groq_api_key=settings.GROQ_API_KEY)
    prompt = f"""Suggest 3 follow-up questions for this database query.
Question: {original_question}
Result: {sql_result_summary}
Schema: {schema_context}
Return ONLY a JSON array of 3 strings."""
    try:
        response = llm.invoke([HumanMessage(content=prompt)])
        content = response.content.strip().replace("```json", "").replace("```", "").strip()
        return json.loads(content)
    except Exception:
        return []

def build_sql_database(connection_config: dict) -> SQLDatabase:
    db_type = connection_config.get("db_type", "").lower()
    if db_type in ("postgresql", "postgres"):
        url = (
            f"postgresql+psycopg2://"
            f"{connection_config['username']}"
            f"@{connection_config['host']}:{connection_config.get('port', 5432)}"
            f"/{connection_config['database']}"
        )
    elif db_type == "mysql":
        url = (
            f"mysql+pymysql://"
            f"{connection_config['username']}:{connection_config['password']}"
            f"@{connection_config['host']}:{connection_config.get('port', 3306)}"
            f"/{connection_config['database']}"
        )
    elif db_type == "sqlite":
        url = f"sqlite:///{connection_config['database']}"
    else:
        raise ValueError(f"Unsupported db_type: {db_type}")
    return SQLDatabase.from_uri(url)

def run_nl_query(agent, question: str) -> dict:
    try:
        response = agent.invoke({"input": question})
        answer = response.get("output", "")
        # If agent hit limit, try direct SQL approach
        if "iteration limit" in answer.lower() or "time limit" in answer.lower():
            return {
                "success": False,
                "question": question,
                "answer": None,
                "error": "Agent hit iteration limit — try a simpler question",
            }
        return {
            "success": True,
            "question": question,
            "answer": answer,
            "error": None,
        }
    except Exception as e:
        return {
            "success": False,
            "question": question,
            "answer": None,
            "error": str(e),
        }

def get_engine():
    db_url = settings.DATABASE_URL
    # Remove ssl params — handled in connect_args
    for param in ["?sslmode=require", "?ssl=require", "?ssl=true", "&sslmode=require"]:
        db_url = db_url.replace(param, "")

    # SSL for both Neon and Supabase
    if any(x in db_url for x in ["neon.tech", "supabase.com", "supabase.co"]):
        ssl_context = ssl.create_default_context()
        ssl_context.check_hostname = False
        ssl_context.verify_mode = ssl.CERT_NONE
        connect_args = {"ssl": ssl_context}
    else:
        connect_args = {}

    return create_async_engine(
        db_url,
        echo=settings.DEBUG,
        pool_pre_ping=True,
        pool_size=5,
        max_overflow=10,
        connect_args=connect_args,
    )

async def get_user_by_email(db: AsyncSession, email: str) -> User | None:
    result = await db.execute(select(User).where(User.email == email))
    return result.scalar_one_or_none()

async def get_user_by_id(db: AsyncSession, user_id: int) -> User | None:
    result = await db.execute(select(User).where(User.id == user_id))
    return result.scalar_one_or_none()

async def get_connections(db: AsyncSession, user_id: int) -> list[DatabaseConnection]:
    result = await db.execute(
        select(DatabaseConnection).where(
            DatabaseConnection.owner_id == user_id,
            DatabaseConnection.is_active == True,
        )
    )
    return result.scalars().all()

async def get_connection_by_id(db: AsyncSession, conn_id: int, user_id: int) -> DatabaseConnection | None:
    result = await db.execute(
        select(DatabaseConnection).where(
            DatabaseConnection.id == conn_id,
            DatabaseConnection.owner_id == user_id,
        )
    )
    return result.scalar_one_or_none()

async def login(form_data: OAuth2PasswordRequestForm = Depends(), db: AsyncSession = Depends(get_db)):
    user = await get_user_by_email(db, form_data.username)
    if not user or not verify_password(form_data.password, user.hashed_password):
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Incorrect email or password")
    if not user.is_active:
        raise HTTPException(status_code=400, detail="Account is inactive")
    token = create_access_token({"sub": user.email})
    return {"access_token": token, "token_type": "bearer"}

