async def ingest_schema(
    db: AsyncSession,
    connection_id: int,
    user_id: int,
) -> dict:
    conn = await get_connection_by_id(db, connection_id, user_id)
    if not conn:
        return {"success": False, "error": "Connection not found"}

    try:
        config  = {"db_type": conn.db_type, "host": conn.host, "port": conn.port,
                   "database": conn.database, "username": conn.username, "password": conn.password or ""}
        handler = get_handler(conn.db_type, config)
        schema  = handler.get_schema()
        handler.dispose()

        documents, metadatas = _schema_to_documents(schema)
        if not documents:
            return {"success": False, "error": "No schema found to ingest"}

        collection_name = _collection_name(connection_id)
        delete_collection(collection_name)

        result = add_documents(
            collection_name=collection_name,
            documents=documents,
            metadatas=metadatas,
        )

        return {
            "success":   True,
            "connection": conn.name,
            "tables":    len(schema),
            "documents": result.get("added", 0),
            "message":   f"Ingested {result.get('added', 0)} documents from {len(schema)} tables",
        }

    except Exception as e:
        return {"success": False, "error": str(e)}

def _conn_to_config(conn: DatabaseConnection) -> dict:
    """Convert our DB model to the config dict handlers expect."""
    return {
        "db_type":  conn.db_type,
        "host":     conn.host,
        "port":     conn.port,
        "database": conn.database,
        "username": conn.username,
        "password": conn.password or "",
    }

def _build_agent_url(conn: DatabaseConnection) -> str:
    """Build sync URL for LangChain SQL Agent."""
    db_type = conn.db_type.lower()
    if db_type in ("postgresql", "postgres"):
        if conn.password:
            return f"postgresql+psycopg2://{conn.username}:{conn.password}@{conn.host}:{conn.port or 5432}/{conn.database}"
        return f"postgresql+psycopg2://{conn.username}@{conn.host}:{conn.port or 5432}/{conn.database}"
    elif db_type == "mysql":
        return f"mysql+pymysql://{conn.username}:{conn.password}@{conn.host}:{conn.port or 3306}/{conn.database}"
    elif db_type == "sqlite":
        return f"sqlite:///{conn.database}"
    elif db_type == "csv":
        return "sqlite://"   # CSV handler manages its own in-memory DB
    raise ValueError(f"Unsupported db_type: {db_type}")

